const alert = $input.first().json;
const severity = (alert.severity || 'UNKNOWN').toUpperCase();
const type = alert.type || 'UNKNOWN';
const srcIp = alert.src_ip || 'N/A';
const dstIp = alert.dst_ip || 'N/A';
const mitre = alert.matched_mitre || alert.mitre_technique || 'N/A';
const score = parseFloat(alert.anomaly_score || alert.rlm_anomaly_score || 0);
const timestamp = alert.timestamp || new Date().toISOString();
const incidentId = `INC-${Date.now()}`;
let playbook = 'STANDARD';
if (type === 'C2_BEACON_DETECTED') playbook = 'C2_RESPONSE';
else if (type === 'ACTIVE_EXPLOITATION') playbook = 'EXPLOIT_RESPONSE';
else if (mitre === 'T1486') playbook = 'RANSOMWARE_RESPONSE';
else if (mitre === 'T1048') playbook = 'EXFIL_RESPONSE';
const emojiMap = { CRITICAL: '🚨', HIGH: '🔴', MEDIUM: '🟠', LOW: '🟡' };
return [{ json: { ...alert, incidentId, severity, type, srcIp, dstIp, mitre, score: score.toFixed(3), timestamp, playbook, emoji: emojiMap[severity] || '⚠️', humanTime: new Date(timestamp).toUTCString(), shouldBlock: severity === 'CRITICAL' && score > 0.8 } }];

const alert = $('Parse & Enrich Alert').item.json;
const hostData = $('Get Host Intelligence').item.json;
const abuseData = $('Check IP Reputation (AbuseIPDB)').item.json?.data || {};
const abuseScore = abuseData.abuseConfidenceScore || 0;
const country = abuseData.countryCode || 'Unknown';
const isp = abuseData.isp || 'Unknown';
const profile = hostData.profile || {};
const anomalyScore = parseFloat(profile.anomaly_score || alert.score || 0);
const combinedScore = (anomalyScore * 0.6 + (abuseScore / 100) * 0.4).toFixed(3);
let verdict = 'INVESTIGATE';
if (combinedScore > 0.75 || abuseScore > 80) verdict = 'MALICIOUS_CONFIRMED';
else if (combinedScore > 0.5 || abuseScore > 50) verdict = 'LIKELY_MALICIOUS';
else if (combinedScore < 0.2 && abuseScore < 10) verdict = 'LIKELY_BENIGN';
return [{ json: { ...alert, hostIntel: { isBlocked: hostData.is_blocked || false, blockCount: hostData.block_count || 0, incidentCount: hostData.incident_count || 0 }, ipReputation: { abuseScore, country, isp, totalReports: abuseData.totalReports || 0 }, combinedScore, verdict, shouldBlock: verdict === 'MALICIOUS_CONFIRMED' && !hostData.is_blocked } }];

const d = $('Correlate Intelligence').item.json;
const blockedLine = d.shouldBlock ? '*Auto-Block:* ✅ IP blocked by SOAR' : '*Auto-Block:* ❌ Not auto-blocked — review in dashboard';
const abuseInfo = d.ipReputation.abuseScore > 0 ? `AbuseIPDB: ${d.ipReputation.abuseScore}% | Country: ${d.ipReputation.country} | ISP: ${d.ipReputation.isp}` : 'AbuseIPDB: No prior reports';
const dashUrl = 'http://localhost:5173';
return [{ json: { channel: 'C0ANVSMJTH9', text: `${d.emoji} CyberSentinel SOAR — ${d.severity}: ${d.type}`, blocks: [{ type: 'header', text: { type: 'plain_text', text: `${d.emoji} ${d.severity} — ${d.type}` } }, { type: 'section', fields: [{ type: 'mrkdwn', text: '*Source IP:*
`' + d.srcIp + '`' }, { type: 'mrkdwn', text: '*Destination:*
`' + d.dstIp + '`' }, { type: 'mrkdwn', text: '*MITRE ATT&CK:*
`' + d.mitre + '`' }, { type: 'mrkdwn', text: '*Playbook:*
`' + d.playbook + '`' }, { type: 'mrkdwn', text: `*Threat Score:*
${d.combinedScore}` }, { type: 'mrkdwn', text: `*Verdict:*
${d.verdict}` }] }, { type: 'section', text: { type: 'mrkdwn', text: `${blockedLine}
${abuseInfo}` } }, { type: 'divider' }, { type: 'context', elements: [{ type: 'mrkdwn', text: 'Incident: `' + d.incidentId + '`  |  ' + d.humanTime + '  |  <' + dashUrl + '|Open Dashboard>' }] }] } }];
